import React from 'react'
import { Avatar, Box, Card, CardActionArea, CardActions, CardContent, CardHeader, CardMedia, Divider, IconButton, Typography } from '@material-ui/core'
import defaultCoverPhoto from '../images/defaultCoverPhoto.png'
import { makeStyles } from '@material-ui/styles'
import { Link } from 'react-router-dom'
import { MoreVert } from '@material-ui/icons'


const useStyle = makeStyles(theme => {
  return {
    root: {
      '& .MuiCardActionArea-focusHighlight': {
        background: 'none',
      },
      '& .MuiCardHeader-title': {

        // width: '100%',
        width: theme.spacing(10)
      },
      '& .MuiCardHeader-subheader': {
        whiteSpace: 'nowrap',
        overflow: 'hidden',
        textOverflow: 'ellipsis',

        // width: '100%',
        width: theme.spacing(35)
      },
    },
    avatar: {
      background: '#162276',
      width: theme.spacing(7),
      height: theme.spacing(7),
    },
    media: {
      height: 0,
      paddingTop: '56.25%'
    },
    cardLink: {
      textDecoration: 'none',
      color: 'inherit'
    },
    card: {
      width: theme.spacing(37),
      [theme.breakpoints.down('xs')]: {
        width: theme.spacing(29),
      },
      boxShadow: '',
      transition: 'all ease-out 0.1s',

      '&:hover': {
        // transform: 'scale(1.01)',
        boxShadow: '2px 5px 7px rgba(0, 0, 0, 0.25)',
        transition: 'all ease-out 0.1s',
        [theme.breakpoints.down('md')]: {
          transform: 'none'
        }
      }
    }
  }
})


export default function ClassroomCards({ subject }) {
  const classes = useStyle()
  const firstName = subject.instructor.split('')[0]
  return (
    <Box className={classes.root}>
      <Card className={classes.card}>



        <CardMedia
          className={classes.media}
          image={defaultCoverPhoto}
        />
        <CardHeader
          title={
            <Link className={classes.cardLink}
              to={`/teacherFeed/${subject.id}`} >
              {subject.subjectName}
            </Link>
          }
          subheader={subject.yearSection}

        />

        <Divider />

        <CardActions>
          <IconButton aria-label="remove" size='smal' onClick={() => { console.log(subject.id); }}>
            <MoreVert />
          </IconButton>
        </CardActions>

      </Card>
    </Box>
  )
}
